import type { PriceComparisonRow } from '../types';
export const PriceComparisonTable=({rows,isLoading}:{rows:PriceComparisonRow[];isLoading:boolean})=>{if(isLoading)return <div className="h-48 animate-pulse rounded-xl bg-slate-100 dark:bg-slate-800"/>;if(!rows.length)return <p className="rounded-xl border border-dashed p-10 text-center text-sm text-slate-500 dark:border-slate-700">Enter an RFQ reference to compare eligible quotations.</p>;return <div className="overflow-x-auto rounded-xl border border-slate-200 dark:border-slate-700"><table className="min-w-full text-left text-sm"><thead className="bg-slate-50 text-xs uppercase text-slate-500 dark:bg-slate-800"><tr><th className="px-4 py-3">Item</th><th className="px-4 py-3">Supplier</th><th className="px-4 py-3">Quotation</th><th className="px-4 py-3">Quantity</th><th className="px-4 py-3">Unit Price</th><th className="px-4 py-3">Lead Time</th></tr></thead><tbody className="divide-y dark:divide-slate-800">{rows.map(r=><tr key={r.item_id} className={r.is_best_price?'bg-emerald-50 dark:bg-emerald-950/20':''}><td className="px-4 py-3"><p className="font-semibold">{r.item_name}</p><p className="text-xs text-slate-400">{r.sku||r.description}</p></td><td className="px-4 py-3">{r.supplier_name}</td><td className="px-4 py-3 font-mono text-xs">{r.quotation_number}</td><td className="px-4 py-3 tabular-nums">{Number(r.quantity).toLocaleString()}</td><td className="px-4 py-3 font-semibold tabular-nums">{r.currency} {Number(r.unit_price).toLocaleString()} {r.is_best_price?<span className="ml-2 rounded-full bg-emerald-100 px-2 py-1 text-xs text-emerald-700">Best</span>:null}</td><td className="px-4 py-3">{r.lead_time_days===null?'—':`${r.lead_time_days} days`}</td></tr>)}</tbody></table></div>;};
